<template>
    <div style="width: 40%; margin-left: 200px">
        <div style="margin-bottom: 40px; margin-left: 280px" >编辑图书</div>
        <el-form :rules="rules" ref="ruleForm" :model="form" label-width="200px">
            <el-form-item label="名称" prop="name">
                <el-input v-model="form.name" placeholder="请输入名称"></el-input>
            </el-form-item>
            <el-form-item label="作者" prop="author">
                <el-input v-model="form.author" placeholder="请输入作者"></el-input>
            </el-form-item>
            <el-form-item label="标准码" prop="bookNo">
                <el-input v-model="form.bookNo" placeholder="请输入标准码"></el-input>
            </el-form-item>
            <el-form-item label="数量" prop="number">
<!--                <el-input v-model="form.score" placeholder="请输入积分"></el-input>-->
                <el-input-number v-model="form.number"  :min="1" :max="10" label="数量"></el-input-number>

            </el-form-item>

          <el-form-item label="出版社" prop="publish">
            <!--                <el-input v-model="ruleForm.publish" placeholder="请输入标准码"></el-input>-->
            <el-cascader
                :props="{value: 'name', label: 'name'}"
                v-model="form.publishes"
                :options="publishes"
                @change="handleChange"></el-cascader>
          </el-form-item>
            <el-form-item label="分类" prop="category">
<!--
 <el-input v-model="form.category" placeholder="请输入分类"></el-input>-->
                <el-cascader
                        :props="{value: 'name', label: 'name'}"
                        v-model="form.categories"
                        :options="categories"
                       ></el-cascader>
            </el-form-item>
          <el-form-item label="区域编号" prop="locationId">
            <el-cascader
                :props="{value: 'id', label: 'id'}"
                v-model="form.locations"
                :options="locations"
                @change="handleChange"></el-cascader>
          </el-form-item>
            <el-form-item label="描述" prop="description">
                <el-input  type="textarea" v-model="form.description" placeholder="请输入描述"></el-input>
            </el-form-item>

        </el-form>
        <div style="text-align: center; margin-top: 30px">
            <el-button type="primary" @click="save">提交</el-button>
        </div>
    </div>
</template>

<script>
    import request from "@/utils/request";
    import Cookies from "js-cookie";
    //导入请求
    export default {
        name: "EditBook",
        data(){
            return {
                admin: Cookies.get('admin') ? JSON.parse(Cookies.get('admin')) : {},
                form: {},
                categories:[],
                publishes:[],
                locations: [],
                rules: {
                    name: [
                        {required: true, message: '请输入图书名称', trigger: 'blur'},
                    ],
                }
            }

        },
        created() {
            request.get('/category/tree').then(res => {
                this.categories = res.data;
            })
          request.get('/publish/list').then(res => {
            this.publishes  = res.data
          })
          request.get('/location/list').then(res => {
            this.locations  = res.data
          })
            const id = this.$route.query.id
            request.get("/book/" + id).then(res =>{
                this.form = res.data
                if(this.form.category){
                    this.form.categories = this.form.category.split('>')
                }
            })
        },
        methods: {
            handleCoverSuccess(res){
                if(res.code === '200'){
                    this.form.cover = res.data;
                }
            },
            save() {
                request.put('/book/update',this.form).then(res =>{
                    if(res.code === '200'){
                        this.$notify.success('更新成功')
                        this.$router.push("/bookList")
                    }else{
                        this.$notify.error(res.msg)
                    }
                })
                //    对接的是后台的UserController.java文件的路径
            },
            handleChange(){

            }
        }
    }
</script>

<style scoped>
    .avatar-uploader .el-upload {
        border: 1px dashed #d9d9d9;
        border-radius: 6px;
        cursor: pointer;
        position: relative;
        overflow: hidden;
    }
    .avatar-uploader .el-upload:hover {
        border-color: #409EFF;
    }
    .avatar-uploader-icon {
        font-size: 28px;
        color: #8c939d;
        width: 178px;
        height: 178px;
        line-height: 178px;
        text-align: center;
    }
    .avatar {
        width: 178px;
        height: 178px;
        display: block;
    }

</style>